    }

    private fun RuleExecutionContext.determineLineSeparator(fileContent: String): String {
        val eol = editorConfig[END_OF_LINE_PROPERTY]
        return when {
            eol == crlf || eol != lf && fileContent.lastIndexOf('\r') != -1 -> "\r\n"
            else -> "\n"
