{"file_path":"/project/ktlint-api-consumer/src/test/kotlin/com/pinterest/ktlint/api/consumer/RerunFormatTest.kt","content":"package com.pinterest.ktlint.api.consumer

import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.api.LintError
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.test.KtlintTestFileSystem
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.tree.IElementType
import org.junit.jupiter.api.AfterEach
import org.junit.jupiter.api.Test

/**
 * Test to verify that format automatically reruns when auto-correctable errors are found,
 * but no more than 3 reruns are performed.
 */
class RerunFormatTest {
    private val ktlintTestFileSystem = KtlintTestFileSystem()

    @AfterEach
    fun tearDown() {
        ktlintTestFileSystem.close()
    }

    /**
     * A test rule that corrects errors over multiple passes
     */
    private class MultiPassCorrectingRule : Rule(
        ruleId = RULE_ID,
        about = About(),
    ) {
        companion object {
            val RULE_ID = RuleId("test:multi-pass-correcting-rule")
        }

        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            if (!autoCorrect) return

            // Find all occurrences of "foo" and replace with "bar"
            // Mark the replacement as an error so it will be reported in the first pass
            val text = node.text
            if ("foo" in text) {
                // Emit error and correct it (emit is called for each occurrence)
                node.text.forEachIndexed { index, char ->
                    val startIndex = node.startOffset + index
                    if (text.indexOf("foo", startIndex) == startIndex && index < text.length - 2) {
                        emit(startIndex, "Replace 'foo' with 'bar'", true)
                        // The actual correction happens in the rule's AST modification
                        if (startIndex >= 0 && startIndex + 3 <= node.textLength) {
                            node.psi?.let {
                                if (it is org.jetbrains.kotlin.com.intellij.psi.LeafElement) {
                                    val newText = text.replace("foo", "bar")
                                    it.rawReplaceWithText(newText)
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    @Test
    fun `format reruns until no auto-correctable errors remain`() {
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { MultiPassCorrectingRule() },
                    ),
                fileSystem = ktlintTestFileSystem.fileSystem,
            )

        val errors = mutableListOf<LintError>()
        val formattedCode =
            ktLintRuleEngine.format(
                code =
                    Code.fromSnippet(
                        """
                        fun test() {
                            val foo = "foo"
                            println(foo)
                        }
                        """.trimIndent(),
                    ),
                callback = { error, corrected ->
                    errors.add(error)
                },
            )

        // After formatting, all occurrences should be replaced
        assertThat(formattedCode)
            .doesNotContain("foo")
            .contains("val bar = \"bar\"")
            .contains("println(bar)")
    }

    @Test
    fun `format stops after max 3 reruns even if errors remain`() {
        // Create a rule that keeps introducing new errors to prevent infinite loops
        val loopingRule =
            object : Rule(
                ruleId = RuleId("test:looping-rule"),
                about = About(),
            ) {
                var callCount = 0

                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                ) {
                    callCount++
                    if (!autoCorrect || callCount > 5) return

                    // Always emit an error that can be auto-corrected
                    if (node.textLength > 1) {
                        emit(node.startOffset, "Test error for rerun", true)
                    }
                }
            }

        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { loopingRule },
                    ),
                fileSystem = ktlintTestFileSystem.fileSystem,
            )

        val errors = mutableListOf<LintError>()
        val callCountBefore = loopingRule.callCount

        ktLintRuleEngine.format(
            code =
                Code.fromSnippet(
                    """
                    fun test() {}
                    """.trimIndent(),
                ),
            callback = { error, corrected ->
                errors.add(error)
            },
        )

        // The rule should be called multiple times but no more than 4 times total (initial + 3 reruns)
        assertThat(loopingRule.callCount).isLessThanOrEqualTo(callCountBefore + 4)
    }

    @Test
    fun `format does not rerun when no auto-correctable errors exist`() {
        val ktLintRuleEngine =
            KtLintRuleEngine(
                ruleProviders = emptySet(),
                fileSystem = ktlintTestFileSystem.fileSystem,
            )

        val originalCode =
            """
            fun test() {
                println("hello")
            }
            """.trimIndent()

        val formattedCode = ktLintRuleEngine.format(code = Code.fromSnippet(originalCode))

        // No changes should be made
        assertThat(formattedCode).isEqualTo(originalCode)
    }
}"}

