import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.ruleset.standard.rules.IndentationRule
import com.pinterest.ktlint.test.KtlintTestFileSystem
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.AfterEach
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Test to verify that format automatically reruns when auto-correctable errors are found,
 * but no more than 3 reruns are performed.
 */
class RerunFormatTest {
    private val ktlintTestFileSystem = KtlintTestFileSystem()

    @AfterEach
    fun tearDown() {
        ktlintTestFileSystem.close()
    }

    @Nested
    inner class FormatRerunsBehavior {
        @Test
        fun `format returns correct code after multiple passes`() {
            val ktLintRuleEngine =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { IndentationRule() },
                        ),
                    fileSystem = ktlintTestFileSystem.fileSystem,
                )

            val formattedCode =
                ktLintRuleEngine.format(
                    code =
                        Code.fromSnippet(
                            """
                            fun main() {
                            println("Hello")
                            }
                            """.trimIndent(),
                        ),
                )

            // Both indentation errors should be fixed
            assertThat(formattedCode)
                .isEqualTo(
                    """
                    fun main() {
                        println("Hello")
                    }
                    """.trimIndent(),
                )
        }

        @Test
        fun `format callback receives errors on each run`() {
            val ktLintRuleEngine =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { IndentationRule() },
                        ),
                    fileSystem = ktlintTestFileSystem.fileSystem,
                )

            val formattedCode =
                ktLintRuleEngine.format(
                    code =
                        Code.fromSnippet(
                            """
                            fun main() {
                            println("Hello")
                            }
                            """.trimIndent(),
                        ),
                    callback = { error, corrected ->
                        // Verify callback receives errors
                        assertThat(error.canBeAutoCorrected).isTrue()
                    },
                )

            assertThat(formattedCode)
                .isEqualTo(
                    """
                    fun main() {
                        println("Hello")
                    }
                    """.trimIndent(),
                )
        }
    }

    @Nested
    inner class MaxRerunsLimit {
        @Test
        fun `format completes without infinite reruns`() {
            // Test with a code that might require multiple passes to ensure it stabilizes
            val ktLintRuleEngine =
                KtLintRuleEngine(
                    ruleProviders =
                        setOf(
                            RuleProvider { IndentationRule() },
                        ),
                    fileSystem = ktlintTestFileSystem.fileSystem,
                )

            // Code with multiple formatting issues
            val formattedCode =
                ktLintRuleEngine.format(
                    code =
                        Code.fromSnippet(
                            """
                            fun test() {
                            val x = 1
                            val y = 2
                            }
                            """.trimIndent(),
                        ),
                )

            // Should complete successfully
            assertThat(formattedCode)
                .isEqualTo(
                    """
                    fun test() {
                        val x = 1
                        val y = 2
                    }
                    """.trimIndent(),
                )
        }
    }
}"}

